/**
 * Specialist: CORS Configuration
 * Checks if CORS is properly configured for server-side applications.
 */

export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

const CORS_PACKAGE_PATTERNS = [
  /^cors$/,
  /^@fastify\/cors$/,
  /^fastify-cors$/,
  /^koa-cors$/,
  /^koa2-cors$/,
  /^@koa\/cors$/,
  /^micro-cors$/,
  /^express-cors$/,
  /^apollo-server-cors$/,
  /^graphql-cors$/,
  /^cors-anywhere$/,
];

const SERVER_DEPS = [
  'express',
  'fastify',
  'koa',
  'hapi',
  'hono',
  'restify',
  'connect',
  'polka',
  '@nestjs/core',
  'next',
  'nuxt',
  '@remix-run/server-runtime',
  '@sveltejs/kit',
  'astro',
  'solid-start',
  'nitro',
  '@hono/node-server',
];

const CORS_CODE_PATTERNS = [
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /['"]hono\/cors['"]/,
  /['"]@fastify\/cors['"]/,
  /cors\s*:\s*(true|{|\[)/i,
  /allowedOrigins?\s*:/i,
  /allowOrigin\s*:/i,
  /enableCors/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /cors\s*\(/i,
];

function hasCorsDependency(deps) {
  if (!deps) return null;
  const keys = Object.keys(deps);
  return keys.find((d) => CORS_PACKAGE_PATTERNS.some((p) => p.test(d))) || null;
}

function hasServerDependency(deps) {
  if (!deps) return false;
  const keys = Object.keys(deps);
  return keys.some((d) => SERVER_DEPS.some((s) => d.includes(s)));
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === 'empty') {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Empty repo — CORS not applicable',
        findings: [],
      };
    }

    const hasCodeFiles = tree.some((p) =>
      /\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)
    );
    if (!hasCodeFiles) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'No JavaScript/TypeScript files — CORS not applicable',
        findings: [],
      };
    }

    const rootDeps = {
      ...packageJson?.dependencies,
      ...packageJson?.devDependencies,
      ...packageJson?.peerDependencies,
    };
    const hasServerDep = hasServerDependency(rootDeps);
    const corsDep = hasCorsDependency(rootDeps);

    if (corsDep) {
      return {
        checkId,
        status: 'pass',
        confidence: 'high',
        message: `CORS dependency found (${corsDep})`,
        findings: [],
      };
    }

    if ((repoType === 'library' || repoType === 'tool') && !hasServerDep) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: `${repoType === 'tool' ? 'Tool' : 'Library'} repo — CORS not applicable`,
        findings: [],
      };
    }

    const isMonorepo = !!(
      packageJson?.workspaces ||
      tree.some(
        (p) =>
          /\/pnpm-workspace\.yaml$/.test(p) ||
          /\/turbo\.json$/.test(p) ||
          /\/lerna\.json$/.test(p)
      )
    );

    if (isMonorepo) {
      const workspacePkgs = tree
        .filter((p) =>
          /\/(packages|apps|examples|libs|services|workers)\/[^/]+\/package\.json$/.test(
            p
          )
        )
        .slice(0, 15);

      for (const pkgPath of workspacePkgs) {
        const content = await files.get(pkgPath);
        if (!content) continue;
        try {
          const pkg = JSON.parse(content);
          const deps = {
            ...pkg.dependencies,
            ...pkg.devDependencies,
            ...pkg.peerDependencies,
          };
          const dep = hasCorsDependency(deps);
          if (dep) {
            return {
              checkId,
              status: 'pass',
              confidence: 'high',
              message: `CORS dependency found in ${pkgPath} (${dep})`,
              findings: [
                { file: pkgPath, issue: 'CORS dependency detected' },
              ],
            };
          }
        } catch (e) {
          // ignore invalid JSON
        }
      }
    }

    const codeFiles = tree.filter((p) => {
      if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) return false;
      if (/(node_modules|\/\.|dist\/|build\/|coverage\/|\.next\/|out\/|\.tmp\/)/.test(p))
        return false;
      return true;
    });

    const configFiles = [];
    const serverFiles = [];
    const apiFiles = [];
    const otherFiles = [];

    for (const p of codeFiles) {
      if (
        /(config|rc)\.(js|ts|mjs|cjs)$/.test(p) ||
        /\/(next|nuxt|astro|vite|nitro|wrangler|remix)\.config/.test(p)
      ) {
        configFiles.push(p);
      } else if (
        /(server|app|index|main|listen)\.(js|ts|mjs|cjs|jsx|tsx)$/.test(p)
      ) {
        serverFiles.push(p);
      } else if (
        /\/(api|routes|controllers|handlers|middleware|plugins)\//.test(p) ||
        /\.route\.(js|ts|jsx|tsx)$/.test(p)
      ) {
        apiFiles.push(p);
      } else {
        otherFiles.push(p);
      }
    }

    const candidateFiles = [
      ...new Set([...configFiles, ...serverFiles, ...apiFiles, ...otherFiles]),
    ].slice(0, 20);

    for (const filePath of candidateFiles) {
      const content = await files.get(filePath);
      if (!content) continue;
      for (const pattern of CORS_CODE_PATTERNS) {
        if (pattern.test(content)) {
          return {
            checkId,
            status: 'pass',
            confidence: 'high',
            message: `CORS configuration found in ${filePath}`,
            findings: [{ file: filePath, issue: 'CORS detected' }],
          };
        }
      }
    }

    const scripts = packageJson?.scripts || {};
    const keywords = packageJson?.keywords || [];
    const name = packageJson?.name || '';
    const isPrivate = packageJson?.private === true;
    const hasWorkspaces = isMonorepo;
    const noServeScript =
      !scripts.start && !scripts.serve && !scripts['start:prod'] && !scripts['start:dev'];

    const toolNamePattern =
      /^(webpack|rollup|esbuild|parcel|babel|gulp|grunt|tsup|unbuild|turbo|turborepo|lerna|nx|vitest|jest|mocha|ava|c8|nyc|eslint|prettier|biome|swc|oxc)$/;
    const toolKeywords = [
      'bundler',
      'build-tool',
      'compiler',
      'transpiler',
      'task-runner',
      'package-manager',
      'testing',
    ];

    if (
      toolNamePattern.test(name) ||
      keywords.some((k) => toolKeywords.includes(k.toLowerCase()))
    ) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Build tool or task runner — CORS not applicable',
        findings: [],
      };
    }

    const hasLibField = !!(
      packageJson?.main ||
      packageJson?.module ||
      packageJson?.exports ||
      packageJson?.types ||
      packageJson?.typings
    );
    const hasPeerDeps = !!(
      packageJson?.peerDependencies &&
      Object.keys(packageJson.peerDependencies).length > 0
    );

    if ((hasLibField || hasPeerDeps) && noServeScript && !hasServerDep) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Library with no server — CORS not applicable',
        findings: [],
      };
    }

    if (isPrivate && hasWorkspaces && noServeScript && !hasServerDep) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Framework or library monorepo — CORS not applicable',
        findings: [],
      };
    }

    const hasApiRoutes = tree.some(
      (p) =>
        /\/api\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p) ||
        /\/pages\/api\//.test(p) ||
        /\/app\/api\//.test(p) ||
        /\/routes\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)
    );
    const hasRootServerFile = tree.some((p) =>
      /^(server|app|index)\.(js|ts|mjs|cjs)$/.test(p)
    );

    if (!hasApiRoutes && !hasRootServerFile && !hasServerDep) {
      const hasFrontend = tree.some(
        (p) =>
          /\/pages\/|\/app\/.*\.(jsx|tsx|vue|svelte)$/.test(p) ||
          /\.html$/.test(p)
      );
      if (hasFrontend || repoType === 'deployable') {
        return {
          checkId,
          status: 'not-applicable',
          confidence: 'high',
          message: 'No API or server routes detected — CORS not applicable',
          findings: [],
        };
      }
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'medium',
        message: 'No server-side code detected — CORS not applicable',
        findings: [],
      };
    }

    if (
      (repoType === 'server' || repoType === 'deployable') &&
      (hasApiRoutes || hasRootServerFile)
    ) {
      return {
        checkId,
        status: 'fail',
        confidence: 'medium',
        message: 'Server or API routes detected, but no CORS configuration found',
        findings: [],
      };
    }

    return {
      checkId,
      status: 'check-it',
      confidence: 'medium',
      message: 'Unable to determine if CORS is required — please review manually',
      findings: [],
    };
  } catch (err) {
    console.error(`[${checkId}] check error:`, err);
    return {
      checkId,
      status: 'check-it',
      confidence: 'low',
      message: `Error during CORS check: ${err.message}`,
      findings: [],
    };
  }
}
